@prefix cdifd: <https://cdif.org/validation/0.1/shacl#> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a schema1:ContactPoint ;
                    schema1:url "https://www.thermofisher.com/contact-us.html" ] ;
            sh:resultMessage "a contact point should be provided; an e-mail address is strongly recommended" ;
            sh:resultPath schema1:email ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:datatype xsd:string ;
                    sh:message "a contact point should be provided; an e-mail address is strongly recommended" ;
                    sh:minCount 1 ;
                    sh:path schema1:email ;
                    sh:pattern "[a-z0-9._%+-]+@[a-z0-9.-]+\\.[a-z]{2,}$" ;
                    sh:severity sh:Info ] ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://orcid.org/0000-0001-8898-3457> ;
            sh:resultMessage "A Person should have a contactPoint (schema:ContactPoint or mailto: IRI)" ;
            sh:resultPath schema1:contactPoint ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:contactPointProperty ] .

